    def _qdrant_filter_from_dict(self, filter: Optional[MetadataFilter]) -> Any:
        if not filter:
            return None

        from qdrant_client.http import models as rest

        return rest.Filter(
            must=[
                condition
                for key, value in filter.items()
                for condition in self._build_condition(key, value)
            ]
        )
